import sys
from typing import List

class Solution:
    def heapify(self, nums: List[int]) -> None:
        n = len(nums)
        for i in range(n // 2 - 1, -1, -1):
            self._max_heapify(nums, i, n)

        def _max_heapify(self, nums: List[int], i: int, n: int) -> None:
            left = 2 * i + 1
            right = 2 * i + 2
            max_index = i
            if left < n and nums[left] > nums[max_index]:
                max_index = left
            if right < n and nums[right] > nums[max_index]:
                max_index = right
            if max_index != i:
                nums[i], nums[max_index] = nums[max_index], nums[i]
                self._max_heapify(nums, max_index, n)

    def solve(self, nums: List[int]) -> List[int]:
        self.heapify(nums)
        return nums

def main():
    solver = Solution()
    nums = list(map(int, input().split()))
    print(*solver.solve(nums))
if __name__ == '__main__':
    main()

# For testing
if __name__ == '__tc__':
    assert Solution().solve([4, 2, 1, 3]) == [4, 3, 1, 2]
    print('passed!')

