#include <bits/stdc++.h>
using namespace std;

class Solution {
 public:
  void heapify(vector<int>& nums) {
   n = nums.size();
   for (int i = n/2 - 1; i >= 0; i--) {
    _max_heapify(nums, i);
   }
  }

  void _max_heapify(vector<int>& nums, int i) {
   left = 2 * i + 1;
   right = 2 * i + 2;
   max_index = i;
   if (left < n && nums[left] > nums[max_index]) max_index = left;
   if (right < n && nums[right] > nums[max_index]) max_index = right;
   if (max_index != i)
    swap(nums[i], nums[max_index]);
    _max_heapify(nums, max_index);
  }

  void solve(vector<int>& nums) {
   heapify(nums);
   for (auto& i : nums) cout << i << ' '; cout << endl;
  }

  int n;
  int left, right, max_index;
};

int main() {
 Solution s;
 s.solve({1, 3, 2, 4});
